def build_cai_weights(codon_usage):
    """
    codon_usage: dict {AA: [(codon, freq), ...]}
    return: dict {CODON: w}, where w = freq / max_freq_for_that_AA
    """
    w = {}
    for aa, lst in codon_usage.items():
        if not lst:
            continue
        max_f = max(freq for codon, freq in lst)
        if max_f <= 0:
            continue
        for codon, freq in lst:
            # w in (0,1], but guard zero
            w[codon] = (freq / max_f) if freq > 0 else 0.0
    return w


def cai(seq, include_stop=False, on_unknown="raise"):
    """
    Compute CAI (Codon Adaptation Index) for a coding sequence.
    seq: RNA or DNA string. (RNA: A,C,G,U) (DNA: A,C,G,T)
         Must be in-frame (len % 3 == 0) unless you allow trailing remainder.
    codon_usage: dict like your CODON_USAGE {AA: [(codon, freq), ...]}
    include_stop: if True, include stop codon weights too (обычно False)
    on_unknown: 'raise' | 'skip' | 'zero'
        - raise: ValueError if a codon not found in weights
        - skip: ignore unknown codons (reduces effective length)
        - zero: treat as w=0 -> CAI becomes 0
    """
    if not isinstance(seq, str):
        raise TypeError("seq must be a string")

    s = seq.strip().upper().replace(" ", "").replace("\n", "")
    if not s:
        return 0.0

    # normalize DNA->RNA (T->U) so it matches CODON_USAGE (which is RNA)
    s = s.replace("T", "U")

    weights = build_cai_weights(CODON_USAGE)

    logs = []
    L = 0

    # process codons in-frame
    n = len(s) - (len(s) % 3)
    for i in range(0, n, 3):
        codon = s[i:i+3]
        if not include_stop and codon in ("UAA", "UAG", "UGA"):
            # обычно стоп не учитывают
            continue

        w = weights.get(codon)
        if w is None:
            if on_unknown == "raise":
                raise ValueError(
                    f"Unknown codon '{codon}' at position {i//3 + 1}")
            if on_unknown == "skip":
                continue
            if on_unknown == "zero":
                return 0.0

        if w <= 0:
            # нулевая частота => CAI=0 (геометрическое среднее)
            return 0.0

        logs.append(math.log(w))
        L += 1

    if L == 0:
        return 0.0

    return math.exp(sum(logs) / L)


