prefix = "TTTATAATTTCTTCTTCCAGAA"  # IRES=22
suffix = "UUAAGCUA"
iresEND = 22


beam = 500
iters = 10
lr = 0.03
epsilon = 0.2
L = 2.5


def exec(props, input, cwd="./"):
    proc = subprocess.run(
        props, input=input + "\n", cwd=cwd,
        capture_output=True, text=True, check=True)
    out_lines = proc.stdout.splitlines()
    err_lines = proc.stderr.splitlines()
    return "\n".join(out_lines + err_lines).split("\n")


def find(lines, Q):
    for l in lines:
        if Q in l:
            return l.split(":")[1].strip()
    return None


def colored_ires(seq, start, color=31):
    return f"\033[1;{color}m{seq[0:start]}\033[m{seq[start+1:]}"


def count_cross_pairs(s: str, k: int):
    stack = []
    cross = 0
    for i, c in enumerate(s):
        if c == '(':
            stack.append(i)
        elif c == ')':
            j = stack.pop()
            cross += (j <= k) != (i <= k)
    return cross


def EFE(seq):
    res = exec([
        "./tools/LinearPartition/linearpartition", "-V", "-d0", "-b0"
    ], seq, "./")
    val = find(res, "Free Energy")
    return float(val.split(' ')[0])


def EnsembleWrapper(seq, init, eps, iresEND=0, lam=0.1):
    params = ["./bin/EnsembleDesign"]
    params += list(map(str, [beam, iters, lr, eps, 1, init]))
    params += ["--prefix", prefix, "--suffix",
               suffix, "--iresEND", str(iresEND),
               "--lambda", str(lam)]
    res = exec(params, seq, "./")
    mRNA = find(res, "Final mRNA")
    print(" ".join(params))

    # Cross-pairs are counted from RNAfold's structure (external). When iresEND=22 the C++ DP
    # forbids IRES-rest pairs (pair_blocked), so the optimizer's model has 0; RNAfold can still
    # predict such pairs -> crp can be >0.
    res = exec(["RNAfold", "--noPS"], mRNA, "./")
    struct = res[1].split(" ")[0]

    crp = count_cross_pairs(struct, 22)

    print(f" - mRNA:  {colored_ires(mRNA, 22)}")
    print(f"          {colored_ires(res[1], 22)}")
    print(f"   CROSS: {crp}  [for {iresEND}]")

    return crp, mRNA, struct


def frange(start, stop, step):
    x = start
    while x <= stop + 1e-12:
        yield x
        x += step


ts = datetime.now().strftime("%Y%m%d_%H%M%S")
res = open(f"test_{ts}.txt", 'w')
res.write("sid\tires\tEps\tLength\tCrosspairs\tCAI\tEFE\tmRNA\tStruct\n")

id = 1
for eps in frange(0.0, 1.0, 0.2):
    for set_name in data:
        for k, seq in enumerate(data[set_name]):
            tmp = exec([
                "./bin/LinearDesign_2D", f"{L:.2f}", "0", "codon_usage_freq_table_human.csv"
            ], seq, "./tools/LinearDesign/")
            init = find(tmp, "mRNA sequence")
            for iresEND in [0, 22]:
                crp, mRNA, struct = EnsembleWrapper(seq, init, eps, iresEND)
                cai_val = cai(mRNA)
                efe = EFE(mRNA)
                result_line = \
                    f"{id}\t{iresEND}\t{eps:.1f}\t{len(seq)}\t{crp}\t" + \
                    f"{cai_val:.3f}\t{efe:.3f}\t{mRNA}\t{struct}"
                print(result_line)
                res.write(result_line + "\n")
            id += 1

res.close()
